const input = $input.first().json.body || $input.first().json || {};

const config = {
  mode: input.mode || 'full',
  trigger: input.trigger || 'manual',
  target_agents: input.target_agents || ['agent_8001kdgp7qbyf4wvhs540be78vew'],
  target_workflows: input.target_workflows || [],
  n8n_eval_webhook: input.n8n_eval_webhook || '{{ $env.WEBHOOK_BASE_URL }}/webhook/parallel-eval-runner-v6',
  elevenlabs_eval_webhook: '{{ $env.WEBHOOK_BASE_URL }}/webhook/elevenlabs-conversation-eval',
  thresholds: {
    n8n_pass_rate_critical: 80,
    n8n_pass_rate_warning: 95,
    elevenlabs_pass_rate_critical: 75,
    elevenlabs_tool_accuracy_critical: 85
  },
  started_at: new Date().toISOString(),
  run_id: `simulation-review_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
};

return [{ json: config }];

const items = $input.all();
const config = $('Parse Config').item.json;

let n8nResults = null;
let elevenlabsResults = null;

for (const item of items) {
  const data = item.json;
  if (data.summary && data.summary.total_tests !== undefined && !data.summary.total_scenarios) {
    n8nResults = data;
  } else if (data.summary && data.summary.total_scenarios !== undefined) {
    elevenlabsResults = data.evaluation || data;
  } else if (data.evaluation) {
    elevenlabsResults = data.evaluation;
  }
}

const n8nPassRate = n8nResults?.summary?.pass_rate ? parseFloat(n8nResults.summary.pass_rate) : 100;
const n8nLatency = n8nResults?.summary?.avg_latency_ms || 0;

const elPassRate = elevenlabsResults?.summary?.pass_rate ? parseFloat(elevenlabsResults.summary.pass_rate) : 100;
const elToolAccuracy = elevenlabsResults?.summary?.avg_tool_accuracy ? parseFloat(elevenlabsResults.summary.avg_tool_accuracy) : 100;

const thresholds = config.thresholds;

let overallStatus = 'OK';
let actions = [];

if (n8nPassRate < thresholds.n8n_pass_rate_critical) {
  overallStatus = 'CRITICAL';
  actions.push({ type: 'n8n_autocorrect', reason: `n8n pass rate ${n8nPassRate}% below critical threshold ${thresholds.n8n_pass_rate_critical}%` });
} else if (n8nPassRate < thresholds.n8n_pass_rate_warning) {
  if (overallStatus !== 'CRITICAL') overallStatus = 'WARNING';
}

if (elPassRate < thresholds.elevenlabs_pass_rate_critical || elToolAccuracy < thresholds.elevenlabs_tool_accuracy_critical) {
  overallStatus = 'CRITICAL';
  actions.push({ type: 'elevenlabs_autocorrect', reason: `ElevenLabs pass rate ${elPassRate}% or tool accuracy ${elToolAccuracy}% below threshold`, agent_id: config.target_agents[0], dominant_pattern: elevenlabsResults?.dominant_pattern });
}

const unifiedMetrics = {
  run_id: config.run_id,
  trigger: config.trigger,
  timestamp: new Date().toISOString(),
  overall_status: overallStatus,
  n8n_stack: {
    pass_rate: n8nPassRate,
    avg_latency_ms: n8nLatency,
    total_tests: n8nResults?.summary?.total_tests || 0,
    failures: n8nResults?.failure_count || 0
  },
  elevenlabs_stack: {
    pass_rate: elPassRate,
    tool_accuracy: elToolAccuracy,
    total_scenarios: elevenlabsResults?.summary?.total_scenarios || 0,
    failures: elevenlabsResults?.summary?.failed || 0,
    dominant_pattern: elevenlabsResults?.dominant_pattern
  },
  actions_required: actions,
  raw_results: { n8n: n8nResults, elevenlabs: elevenlabsResults }
};

return [{ json: unifiedMetrics }];

const metrics = $input.first().json;
const actions = metrics.actions_required || [];

const actionItems = [];
for (const action of actions) {
  if (action.type === 'elevenlabs_autocorrect') {
    actionItems.push({
      json: {
        action_type: 'elevenlabs',
        webhook: '{{ $env.WEBHOOK_BASE_URL }}/webhook/autorefinement-trigger',
        payload: {
          agent_id: action.agent_id,
          dominant_pattern: action.dominant_pattern,
          failures: metrics.raw_results.elevenlabs?.detailed_results?.filter(r => !r.passed) || [],
          total_tests: metrics.elevenlabs_stack.total_scenarios,
          passed_tests: metrics.elevenlabs_stack.total_scenarios - metrics.elevenlabs_stack.failures,
          source: 'simulation-review-orchestrator'
        }
      }
    });
  }
  if (action.type === 'n8n_autocorrect') {
    actionItems.push({
      json: {
        action_type: 'n8n',
        webhook: null,
        payload: { reason: action.reason, failures: metrics.raw_results.n8n?.failures_by_category || {} }
      }
    });
  }
}

if (actionItems.length === 0) {
  actionItems.push({ json: { action_type: 'none', payload: {} } });
}

return actionItems;
